using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    [ColumnName("Category")]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedLabel { get; set; } = string.Empty;

    [ColumnName("Score")]
    public float[] Score { get; set; } = [];
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelTrainer : IHostedService
{
    private readonly ILogger<TicketModelTrainer> _logger;
    private readonly IWebHostEnvironment _env;

    public TicketModelTrainer(ILogger<TicketModelTrainer> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _env = env;
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(_env.ContentRootPath, "Data", "tickets.csv");
        _logger.LogInformation("Loading training data from {DataPath}", dataPath);

        var dataView = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath,
            hasHeader: true,
            separatorChar: ',',
            allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("Model evaluation metrics:");
        _logger.LogInformation("  MicroAccuracy: {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  MacroAccuracy: {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  LogLoss:       {LogLoss:F4}", metrics.LogLoss);

        var modelPath = Path.Combine(_env.ContentRootPath, "Data", "TicketClassifierModel.zip");
        mlContext.Model.Save(model, dataView.Schema, modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;

    public TicketClassifierController(PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public IActionResult Classify([FromBody] TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var labels = new[] { "Billing", "General", "Technical" };
        var probabilities = labels
            .Zip(prediction.Score, (label, score) => new { label, score })
            .ToDictionary(x => x.label, x => Math.Round(x.score, 4));

        return Ok(new
        {
            PredictedCategory = prediction.PredictedLabel,
            Confidence = Math.Round(prediction.Score.Max(), 4),
            Probabilities = probabilities
        });
    }
}

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public float Priority { get; set; }
}

